var positions = { LoggedOut: [0, 0], Authenticating: [1, 0], AuthError: [1, 1], Idle: [2, 0], Initializing: [3, 0], Loading: [4, 0], Error: [4, 1], FatalError: [3, 1], Ready: [5, 0], Stopped: [5, 1], Running: [6, 0], Paused: [6, 1] };
var nodesMap = {};
rawData.rows.forEach(function(r) { nodesMap[r.from] = true; nodesMap[r.to] = true; });
var nodes = Object.keys(nodesMap).map(function(k) { return { name: k, x: (positions[k] ? positions[k][0] : 0) * 100, y: (positions[k] ? positions[k][1] : 0) * 100 }; });
var links = rawData.rows.map(function(r) { return { source: r.from, target: r.to, label: { show: true, formatter: r.event, fontSize: 10 } }; });
transformedData = { nodes: nodes, links: links };
